// ═══════════════════════════════════════════════════════════════════
// MOTOR DE ORÇAMENTO INTERNO DL SOLUÇÕES — v3.0
// Gera DOIS documentos: Cliente (sanitizado) e Interno (completo)
// ═══════════════════════════════════════════════════════════════════

const b = $input.item.json.body || $input.item.json;
const agora = new Date().toISOString().slice(0, 10);
const hora = new Date().toLocaleTimeString('pt-BR');

// ── Parse de listas JSON ──
let servicos = [];
try { servicos = JSON.parse(b.servicos_lista || '[]'); } catch(e) { servicos = [b.servicos || 'Não informado']; }
let chapa = [];
try { chapa = JSON.parse(b.chapa_lista || '[]'); } catch(e) { chapa = []; }
let modalidade = [];
try { modalidade = JSON.parse(b.modalidade_lista || '[]'); } catch(e) { modalidade = []; }

// ── Dados do cliente ──
const nome = b.nome_cliente || 'Cliente não identificado';
const endereco = b.endereco || 'Não informado';
const tipo = b.tipo_cliente || 'Não informado';
const tipoOutro = b.tipo_cliente_outro || '';
const documento = b.documento || 'Não informado';
const telefone = b.telefone || 'Não informado';
const email = b.email_cliente || 'Não informado';

// ── Análise do local ──
const descLocal = b.descricao_local || 'Não descrito';
const estacionamento = b.estacionamento || 'Não informado';
const escada = b.escada || 'Não';

// ── Dados elétricos ──
const voltagem = b.voltagem || 'Não medido';
const voltagemOutro = b.voltagem_outro || '';
const hz = b.frequencia_hz || '60Hz';
const amperagem = b.amperagem || 'Não medido';
const rede = b.rede_eletrica || 'Não identificado';
const concessionaria = b.concessionaria || 'Light';

// ── Logística ──
const urgencia = b.urgencia || 'Normal';
const tempoExec = b.tempo_execucao || 'A definir';
const tempoDeslocamento = b.tempo_deslocamento || 'A calcular';
const qtdProf = b.qtd_profissionais || '1';
const tempoEntrega = b.tempo_entrega || '3-7 dias';

// ── Chapa / Infra ──
const chapaOutros = b.chapa_outros || '';
const detalheInfra = b.detalhe_infra || '';
const observacoes = b.observacoes || '';

// ── Dados internos (NÃO VAI PRO CLIENTE) ──
const materialInterno = b.material_interno || '';
const custoInterno = b.custo_interno || '';
const notasInternas = b.notas_internas || '';

// ── Multiplicadores de urgência ──
const multUrgencia = { 'Normal': 1.0, 'Urgência': 1.5, 'Emergência': 2.5 };
const mult = multUrgencia[urgencia] || 1.0;

// ═══════════════════════════════════════════
// DOCUMENTO 1: ORÇAMENTO CLIENTE (SANITIZADO)
// ═══════════════════════════════════════════
let docCliente = `# ORÇAMENTO — DL SOLUÇÕES CONDOMINIAIS LTDA\n`;
docCliente += `## Orçamento Cliente: ${nome}\n\n`;
docCliente += `**Data:** ${agora} | **Hora:** ${hora}\n`;
docCliente += `**Cliente:** ${nome}\n`;
docCliente += `**Endereço:** ${endereco}\n`;
docCliente += `**Tipo:** ${tipo} ${tipoOutro}\n`;
docCliente += `**Contato:** ${telefone}\n\n`;
docCliente += `---\n\n`;

docCliente += `### Serviços Solicitados\n\n`;
servicos.forEach(s => { docCliente += `- ✅ ${s}\n`; });
if (chapa.length > 0) {
  docCliente += `\n**Chapa:** ${chapa.join(', ')} ${chapaOutros ? '| ' + chapaOutros : ''}\n`;
}
if (detalheInfra) docCliente += `\n**Infraestrutura:** ${detalheInfra}\n`;

docCliente += `\n### Condições\n\n`;
docCliente += `| Item | Detalhe |\n`;
docCliente += `|------|---------|\n`;
docCliente += `| Prioridade | ${urgencia} |\n`;
docCliente += `| Prazo estimado | ${tempoEntrega} |\n`;
docCliente += `| Execução estimada | ${tempoExec} |\n`;
docCliente += `| Modalidade | ${modalidade.join(', ') || 'A definir'} |\n`;
docCliente += `\n`;

docCliente += `### Materiais\n\n`;
docCliente += `> Os materiais e equipamentos serão especificados com nome comercial DL Soluções. `;
docCliente += `Detalhamento técnico completo (fabricante, modelo, part number) será fornecido `;
docCliente += `**somente após a assinatura do contrato**.\n\n`;

// ── Pré-Contrato / Cláusula de Sigilo ──
if (modalidade.includes('Contrato Recorrente')) {
  docCliente += `### Pré-Contrato — Cláusula de Confidencialidade\n\n`;
  docCliente += `Este documento constitui um **pré-contrato** de intenção de prestação de serviços. `;
  docCliente += `Ao receber este orçamento, o destinatário concorda com as seguintes condições:\n\n`;
  docCliente += `1. **Confidencialidade:** As informações contidas neste documento, incluindo `;
  docCliente += `valores, especificações técnicas, escopo e condições comerciais, são de uso `;
  docCliente += `exclusivo do destinatário listado acima. É **estritamente proibida** a divulgação, `;
  docCliente += `reprodução, encaminhamento ou compartilhamento total ou parcial deste documento `;
  docCliente += `com terceiros, empresas, profissionais ou pessoas não listadas neste instrumento, `;
  docCliente += `sob pena de responsabilização civil e criminal nos termos da legislação vigente.\n\n`;
  docCliente += `2. **Vigência:** Este pré-contrato tem validade de 15 (quinze) dias corridos a partir `;
  docCliente += `da data de emissão.\n\n`;
  docCliente += `3. **Exclusividade de informações:** As soluções técnicas apresentadas são propriedade `;
  docCliente += `intelectual da DL Soluções Condominiais LTDA e não podem ser replicadas ou adaptadas `;
  docCliente += `por empresas concorrentes sem autorização expressa.\n\n`;
}

docCliente += `---\n`;
docCliente += `*DL Soluções Condominiais LTDA — CREA-RJ*\n`;
docCliente += `*contato@dlsolucoescondominiais.com.br*\n`;

// ═══════════════════════════════════════════
// DOCUMENTO 2: ORÇAMENTO INTERNO DL (COMPLETO)
// ═══════════════════════════════════════════
let docInterno = `# ORÇAMENTO INTERNO DL — CONFIDENCIAL\n`;
docInterno += `## Orçamento Interno DL: ${nome}\n\n`;
docInterno += `**⚠️ DOCUMENTO INTERNO — NÃO ENVIAR AO CLIENTE**\n\n`;
docInterno += `**Data:** ${agora} | **Hora:** ${hora}\n`;
docInterno += `**Cliente:** ${nome}\n`;
docInterno += `**Endereço:** ${endereco}\n`;
docInterno += `**Tipo:** ${tipo} ${tipoOutro}\n`;
docInterno += `**Documento:** ${documento}\n`;
docInterno += `**Telefone/WhatsApp:** ${telefone}\n`;
docInterno += `**E-mail:** ${email}\n\n`;
docInterno += `---\n\n`;

docInterno += `### 📍 Análise do Local\n\n`;
docInterno += `| Campo | Valor |\n`;
docInterno += `|-------|-------|\n`;
docInterno += `| Descrição | ${descLocal} |\n`;
docInterno += `| Estacionamento | ${estacionamento} |\n`;
docInterno += `| Escada | ${escada} |\n`;
docInterno += `| Deslocamento | ${tempoDeslocamento} |\n`;
docInterno += `\n`;

docInterno += `### ⚡ Dados Elétricos\n\n`;
docInterno += `| Campo | Valor |\n`;
docInterno += `|-------|-------|\n`;
docInterno += `| Voltagem | ${voltagem} ${voltagemOutro} |\n`;
docInterno += `| Amperagem | ${amperagem} |\n`;
docInterno += `| Frequência | ${hz} |\n`;
docInterno += `| Rede | ${rede} |\n`;
docInterno += `| Concessionária | ${concessionaria} |\n`;
docInterno += `\n`;

docInterno += `### 🔧 Serviços\n\n`;
servicos.forEach(s => { docInterno += `- ✅ ${s}\n`; });
if (chapa.length > 0) docInterno += `\n**Chapa:** ${chapa.join(', ')} ${chapaOutros ? '| ' + chapaOutros : ''}\n`;
if (detalheInfra) docInterno += `\n**Infra:** ${detalheInfra}\n`;
docInterno += `\n`;

docInterno += `### 🚛 Logística\n\n`;
docInterno += `| Campo | Valor |\n`;
docInterno += `|-------|-------|\n`;
docInterno += `| Urgência | ${urgencia} (multiplicador: x${mult}) |\n`;
docInterno += `| Tempo de Execução | ${tempoExec} |\n`;
docInterno += `| Prazo de Entrega | ${tempoEntrega} |\n`;
docInterno += `| Profissionais | ${qtdProf} |\n`;
docInterno += `| Modalidade | ${modalidade.join(', ') || 'A definir'} |\n`;
docInterno += `\n`;

docInterno += `### 🔐 Material (FABRICANTE / MODELO / HARDWARE)\n\n`;
docInterno += `\'\'\'\n${materialInterno || 'Não especificado pelo solicitante'}\n\'\'\'\n\n`;

docInterno += `### 💰 Custo Interno\n\n`;
docInterno += `**Custo estimado:** ${custoInterno || 'A calcular'}\n\n`;

if (notasInternas) {
  docInterno += `### 📝 Notas Internas\n\n`;
  docInterno += `${notasInternas}\n\n`;
}

if (observacoes) {
  docInterno += `### 📌 Observações do Solicitante\n\n`;
  docInterno += `${observacoes}\n\n`;
}

docInterno += `---\n`;
docInterno += `*Gerado automaticamente pelo DL Nexus — Motor de Orçamento v3.0*\n`;

// ── Definir destinos ──
const emailDestino = 'orcamento@dlsolucoescondominiais.com.br';
const contatoCliente = email !== 'Não informado' ? email : telefone;

return [{
  json: {
    status: 'orcamento_gerado',
    data: agora,
    cliente: nome,
    contato_cliente: contatoCliente,
    telefone_cliente: telefone,
    email_cliente: email,
    urgencia: urgencia,
    multiplicador_urgencia: mult,
    orcamento_cliente_md: docCliente,
    orcamento_interno_md: docInterno,
    email_destino_interno: emailDestino,
    assunto_cliente: `Orçamento Cliente — ${nome} — ${agora}`,
    assunto_interno: `Orçamento Interno DL — ${nome} — ${agora}`,
    enviar_whatsapp: email === 'Não informado' ? true : false,
    enviar_email: email !== 'Não informado' ? true : false
  }
}];
